// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title CaveatEnforcers
 * @dev Collection of caveat enforcer contracts for custom permission models
 */

/**
 * @dev Enforcer for native token transfer amount limits
 */
contract NativeTokenTransferAmountEnforcer {
    mapping(bytes32 => uint256) public spentAmount;
    mapping(bytes32 => uint256) public maxAmount;
    mapping(bytes32 => uint256) public resetTime;

    event CaveatEnforced(
        bytes32 indexed delegationId,
        uint256 spent,
        uint256 maxAmount
    );

    /**
     * @dev Enforce amount limit on native token transfers
     * @param delegationId The delegation being redeemed
     * @param terms Encoded max amount and period
     * @param callData The call being made
     */
    function enforceCaveat(
        bytes32 delegationId,
        bytes calldata terms,
        bytes calldata callData
    ) external returns (bool) {
        (uint256 max, uint256 period) = abi.decode(terms, (uint256, uint256));

        // Reset if period has passed
        if (block.timestamp > resetTime[delegationId] + period) {
            spentAmount[delegationId] = 0;
            resetTime[delegationId] = block.timestamp;
        }

        // Extract amount from call data (assumes transfer function)
        uint256 value = _extractCallValue(callData);

        require(spentAmount[delegationId] + value <= max, "Amount exceeds limit");

        spentAmount[delegationId] += value;
        maxAmount[delegationId] = max;

        emit CaveatEnforced(delegationId, spentAmount[delegationId], max);
        return true;
    }

    function getRemainingBudget(bytes32 delegationId)
        external
        view
        returns (uint256)
    {
        return maxAmount[delegationId] - spentAmount[delegationId];
    }

    function _extractCallValue(bytes calldata callData)
        internal
        pure
        returns (uint256)
    {
        // Simplified: extract amount from transfer call
        if (callData.length >= 68) {
            return uint256(bytes32(callData[36:68]));
        }
        return 0;
    }
}

/**
 * @dev Enforcer for time-bound permissions
 */
contract TimeBoundEnforcer {
    event TimeBoundEnforced(
        bytes32 indexed delegationId,
        uint256 startTime,
        uint256 endTime
    );

    /**
     * @dev Enforce time window for delegation use
     * @param delegationId The delegation being redeemed
     * @param terms Encoded start and end times
     * @param callData The call being made
     */
    function enforceCaveat(
        bytes32 delegationId,
        bytes calldata terms,
        bytes calldata callData
    ) external returns (bool) {
        (uint256 startTime, uint256 endTime) = abi.decode(
            terms,
            (uint256, uint256)
        );

        require(
            block.timestamp >= startTime && block.timestamp <= endTime,
            "Outside time window"
        );

        emit TimeBoundEnforced(delegationId, startTime, endTime);
        return true;
    }

    function isTimeValid(
        uint256 startTime,
        uint256 endTime
    ) external view returns (bool) {
        return block.timestamp >= startTime && block.timestamp <= endTime;
    }
}

/**
 * @dev Enforcer for allowed targets and methods
 */
contract AllowedTargetsEnforcer {
    mapping(bytes32 => address[]) public allowedTargets;

    event TargetAllowed(bytes32 indexed delegationId, address indexed target);
    event TargetEnforced(bytes32 indexed delegationId, address target);

    function addAllowedTarget(bytes32 delegationId, address target) external {
        allowedTargets[delegationId].push(target);
        emit TargetAllowed(delegationId, target);
    }

    /**
     * @dev Enforce allowed targets
     * @param delegationId The delegation being redeemed
     * @param terms Encoded target whitelist
     * @param callData The call being made
     */
    function enforceCaveat(
        bytes32 delegationId,
        bytes calldata terms,
        bytes calldata callData
    ) external returns (bool) {
        address[] memory targets = abi.decode(terms, (address[]));

        // In real implementation, would check target from call context
        // For now, simplified check
        require(targets.length > 0, "No targets allowed");

        emit TargetEnforced(delegationId, targets[0]);
        return true;
    }

    function getAllowedTargets(bytes32 delegationId)
        external
        view
        returns (address[] memory)
    {
        return allowedTargets[delegationId];
    }
}

/**
 * @dev Enforcer for allowed methods/functions
 */
contract AllowedMethodsEnforcer {
    mapping(bytes32 => bytes4[]) public allowedMethods;

    event MethodAllowed(
        bytes32 indexed delegationId,
        bytes4 indexed methodSelector
    );

    function addAllowedMethod(bytes32 delegationId, bytes4 methodSelector)
        external
    {
        allowedMethods[delegationId].push(methodSelector);
        emit MethodAllowed(delegationId, methodSelector);
    }

    /**
     * @dev Enforce allowed methods
     * @param delegationId The delegation being redeemed
     * @param terms Encoded method selectors
     * @param callData The call being made
     */
    function enforceCaveat(
        bytes32 delegationId,
        bytes calldata terms,
        bytes calldata callData
    ) external returns (bool) {
        bytes4[] memory methods = abi.decode(terms, (bytes4[]));

        // Extract method selector from callData
        bytes4 methodSelector = bytes4(callData[:4]);

        bool allowed = false;
        for (uint256 i = 0; i < methods.length; i++) {
            if (methods[i] == methodSelector) {
                allowed = true;
                break;
            }
        }

        require(allowed, "Method not allowed");
        return true;
    }

    function getAllowedMethods(bytes32 delegationId)
        external
        view
        returns (bytes4[] memory)
    {
        return allowedMethods[delegationId];
    }
}

/**
 * @dev Enforcer for rate limiting (actions per time period)
 */
contract RateLimitEnforcer {
    mapping(bytes32 => uint256) public actionCount;
    mapping(bytes32 => uint256) public lastResetTime;

    event RateLimited(
        bytes32 indexed delegationId,
        uint256 currentCount,
        uint256 maxPerHour
    );

    /**
     * @dev Enforce rate limiting
     * @param delegationId The delegation being redeemed
     * @param terms Encoded max actions per hour
     * @param callData The call being made
     */
    function enforceCaveat(
        bytes32 delegationId,
        bytes calldata terms,
        bytes calldata callData
    ) external returns (bool) {
        uint256 maxPerHour = abi.decode(terms, (uint256));

        // Reset if hour has passed
        if (block.timestamp > lastResetTime[delegationId] + 1 hours) {
            actionCount[delegationId] = 0;
            lastResetTime[delegationId] = block.timestamp;
        }

        require(actionCount[delegationId] < maxPerHour, "Rate limit exceeded");

        actionCount[delegationId]++;

        emit RateLimited(delegationId, actionCount[delegationId], maxPerHour);
        return true;
    }

    function getRemainingActions(
        bytes32 delegationId,
        uint256 maxPerHour
    ) external view returns (uint256) {
        uint256 current = actionCount[delegationId];
        if (maxPerHour > current) {
            return maxPerHour - current;
        }
        return 0;
    }
}

contracts/DelegationManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title DelegationManager
 * @dev ERC-7715 compliant delegation management contract
 * Implements hierarchical delegation chains with custom caveats
 * Deployed on Ethereum Sepolia Testnet for DelegateFlow Hackathon
 */

interface IDelegationManager {
    event DelegationCreated(
        bytes32 indexed delegationId,
        address indexed delegator,
        address indexed delegate,
        bytes32 authority
    );
    event DelegationRevoked(bytes32 indexed delegationId);
    event DelegationRedeemed(
        bytes32 indexed delegationId,
        address indexed redeemer,
        bytes callData
    );
    event CaveatEnforced(bytes32 indexed delegationId, address indexed enforcer);

    struct Caveat {
        address enforcer;
        bytes terms;
        bytes args;
    }

    struct Delegation {
        address delegator;
        address delegate;
        bytes32 authority;
        Caveat[] caveats;
        bytes32 salt;
        uint256 createdAt;
        uint256 expiresAt;
        bool revoked;
    }

    function createDelegation(
        address delegator,
        address delegate,
        bytes32 authority,
        Caveat[] calldata caveats,
        bytes32 salt,
        uint256 expiresAt
    ) external returns (bytes32);

    function revokeDelegation(bytes32 delegationId) external;

    function redeemDelegation(
        bytes32 delegationId,
        address target,
        bytes calldata callData
    ) external payable returns (bytes memory);

    function validateCaveats(bytes32 delegationId, bytes calldata context)
        external
        view
        returns (bool);

    function getDelegation(bytes32 delegationId)
        external
        view
        returns (
            address delegator,
            address delegate,
            bytes32 authority,
            bytes32 salt,
            uint256 createdAt,
            uint256 expiresAt,
            bool revoked
        );

    function getSubDelegations(bytes32 parentId)
        external
        view
        returns (bytes32[] memory);
}

contract DelegationManager is IDelegationManager {
    // --- State ---
    struct StoredDelegation {
        address delegator;
        address delegate;
        bytes32 authority;
        bytes32 salt;
        uint256 createdAt;
        uint256 expiresAt;
        bool revoked;
    }

    mapping(bytes32 => StoredDelegation) public storedDelegations;
    mapping(bytes32 => IDelegationManager.Caveat[]) public delegationCaveats;
    mapping(bytes32 => bytes32[]) public subDelegations;

    uint256 public totalDelegations;

    // --- Core Functions ---

    function createDelegation(
        address delegator,
        address delegate,
        bytes32 authority,
        IDelegationManager.Caveat[] calldata caveats,
        bytes32 salt,
        uint256 expiresAt
    ) external returns (bytes32) {
        bytes32 delegationId = keccak256(
            abi.encodePacked(delegator, delegate, salt, block.chainid)
        );

        require(
            storedDelegations[delegationId].delegator == address(0),
            "Delegation already exists"
        );

        // Store delegation
        storedDelegations[delegationId] = StoredDelegation({
            delegator: delegator,
            delegate: delegate,
            authority: authority,
            salt: salt,
            createdAt: block.timestamp,
            expiresAt: expiresAt,
            revoked: false
        });

        // Store caveats separately to avoid storage overwrite bug
        for (uint256 i = 0; i < caveats.length; i++) {
            delegationCaveats[delegationId].push(caveats[i]);
        }

        // Link sub-delegation to parent
        if (authority != bytes32(0)) {
            subDelegations[authority].push(delegationId);
        }

        totalDelegations++;
        emit DelegationCreated(delegationId, delegator, delegate, authority);
        return delegationId;
    }

    function revokeDelegation(bytes32 delegationId) external {
        StoredDelegation storage del = storedDelegations[delegationId];
        require(del.delegator == msg.sender, "Only delegator can revoke");
        require(!del.revoked, "Already revoked");
        del.revoked = true;
        emit DelegationRevoked(delegationId);
    }

    function redeemDelegation(
        bytes32 delegationId,
        address target,
        bytes calldata callData
    ) external payable returns (bytes memory) {
        StoredDelegation storage del = storedDelegations[delegationId];
        require(del.delegator != address(0), "Delegation does not exist");
        require(!del.revoked, "Delegation revoked");
        require(block.timestamp <= del.expiresAt, "Delegation expired");
        require(del.delegate == msg.sender, "Only delegate can redeem");

        // Enforce all caveats
        IDelegationManager.Caveat[] storage caveats = delegationCaveats[delegationId];
        for (uint256 i = 0; i < caveats.length; i++) {
            _enforceCaveat(delegationId, caveats[i], callData);
        }

        // Execute the delegated call
        (bool success, bytes memory result) = target.call{value: msg.value}(callData);
        require(success, "Delegated call failed");

        emit DelegationRedeemed(delegationId, msg.sender, callData);
        return result;
    }

    function validateCaveats(bytes32 delegationId, bytes calldata /*context*/)
        external
        view
        returns (bool)
    {
        StoredDelegation storage del = storedDelegations[delegationId];
        if (del.revoked) return false;
        if (block.timestamp > del.expiresAt) return false;
        return true;
    }

    function getDelegation(bytes32 delegationId)
        external
        view
        returns (
            address delegator,
            address delegate,
            bytes32 authority,
            bytes32 salt,
            uint256 createdAt,
            uint256 expiresAt,
            bool revoked
        )
    {
        StoredDelegation storage del = storedDelegations[delegationId];
        return (
            del.delegator,
            del.delegate,
            del.authority,
            del.salt,
            del.createdAt,
            del.expiresAt,
            del.revoked
        );
    }

    function getSubDelegations(bytes32 parentId)
        external
        view
        returns (bytes32[] memory)
    {
        return subDelegations[parentId];
    }

    function getCaveats(bytes32 delegationId)
        external
        view
        returns (IDelegationManager.Caveat[] memory)
    {
        return delegationCaveats[delegationId];
    }

    // --- Internal ---

    function _enforceCaveat(
        bytes32 delegationId,
        IDelegationManager.Caveat storage caveat,
        bytes calldata callData
    ) internal {
        if (caveat.enforcer == address(0)) return; // Skip null enforcers
        (bool success, ) = caveat.enforcer.staticcall(
            abi.encodeWithSignature(
                "enforceCaveat(bytes32,bytes,bytes)",
                delegationId,
                caveat.terms,
                callData
            )
        );
        require(success, "Caveat enforcement failed");
        emit CaveatEnforced(delegationId, caveat.enforcer);
    }
}

